num, arcnum; //顶点数，弧数&#125;MGraph;int vex_six_num[MAX_VERTEX_NUM];void Creatgraph(MGraph &amp;G)&#123; int i, j, k; cin&gt;&gt;G.vexnum&gt;&gt;G.arcnum; for(i=0; i&lt;G.vexnum;++i)&#123; for(j=0; j&lt;G.vexnum; ++j)&#123; G.arcs[i][j].adj=0; G.arcs[j][i].adj=0; &#125; &#125; for(k=0; k&lt;G.arcnum; ++k)&#123; cin&gt;&gt;i&gt;&gt;j; G.arcs[i-1][j-1].adj=1; G.arcs[j-1][i-1].adj=1; &#125;&#125;void BFSTraver(MGraph G, int v)&#123; int count=0; int visited[G.vexnum]; for(int i=0; i&lt;G.vexnum; ++i)&#123; visited[i]=0; &#125; queue&lt;int&gt; Q; visited[v]=1; Q.push(v); while(!Q.empty() &amp;&amp; count&lt;=6)&#123; int num=Q.size(); int array[num]; vex_six_num[v] += num; for(int i=0; i&lt;num; ++i)&#123; array[i]=Q.front(); Q.pop(); &#125; for(int i=0; i&lt;num; ++i)&#123; for(int w=0; w&lt;G.vexnum; ++w)&#123; if(G.arcs[w][array[i]].adj &amp;&amp; !visited[w])&#123; visited[w]=1; Q.push(w); &#125; &#125; &#125; ++count; &#125;&#125;int main()&#123; MGraph G; Creatgraph(G); for(int i=0; i&lt;G.vexnum; ++i)&#123; vex_six_num[i]=0; &#125; for(int i=0; i&lt;G.vexnum; ++i)&#123; BFSTraver(G, i); &#125; for(int i=0; i&lt;G.vexnum; ++i)&#123; printf(&quot;%d: %.2f%%
&quot;, i+1, 100*(float)vex_six_num[i]/G.vexnum); &#125; return 0;&#125; 实验四 倒排索引和散列函数 /*实验四---倒排索引由单词确定文件位置*/#include &quot;iostream&quot;#include &quot;cstdio&quot;#include &quot;ctype.h&quot;#include &quot;cstring&quot;using namespace std;/*类似拉链法文件链表结点结构*/typedef struct File_node&#123; int numbering;//文件编号 File_node *next;&#125;File_node;//word链表结点结构typedef struct Word_node&#123; char word[10]; Word_node *nextword; File_node *file;&#125;Word_node;//散列表typedef struct Position&#123; Word_node *next;&#125;Position;Position WORD[10000];//存放每一个文件中单词的个数int File_word_num[100];int Make_Hash(char* word)&#123; unsigned int h=0; char temp[11]; char *tt=&amp;temp[0]; strcpy(temp, word); while(*tt != &#x27;\0&#x27;)&#123; h = (h&lt;&lt;5)+(*tt++ -&#x27;a&#x27;); &#125; return h%10000;&#125;void Storage(char *word, int pos, int numbering)&#123; //先查找,在Position[pos]中查找 Word_node *m=WORD[pos].next; while(m!=NULL)&#123; if(!strcmp(m-&gt;word, word)) break; m=m-&gt;nextword; &#125; if(m!=NULL)&#123; File_node *p=new File_node; p-&gt;numbering=numbering; p-&gt;next=m-&gt;file; m-&gt;file=p; &#125;else&#123; Word_node *p=new Word_node; File_node *q=new File_node; strcpy(p-&gt;word, word); p-&gt;nextword=WORD[pos].next; WORD[pos].next=p; p-&gt;file=NULL; q-&gt;numbering=numbering; q-&gt;next=p-&gt;file; p-&gt;file=q; &#125;&#125;void Input()&#123; int num; cin&gt;&gt;num;//文件总数 char word[11];//单词最长为10 int i;//计数，单词长度 int m=0;//记录文件中单词的个数 int pos; char c; for(int j=0; j&lt;num; ++j)&#123; i=0; while(1)&#123; //控制一个文件的输入，以#为结束条件 c=cin.get(); while(isalpha(c) != 0 &amp;&amp; i&lt;10)&#123; //输入的一个字符是字母 //统一为小写字母 if(c&lt;&#x27;a&#x27;) c+=32; //放入word[10]中 word[i]=c; ++i; c=cin.get(); &#125; if(c==&#x27;#&#x27;)&#123; for(int i=10; i&gt;=0; --i)&#123; word[i]=&#x27;\0&#x27;; &#125; i = 0; break; &#125;else if(i&gt;=3 &amp;&amp; i&lt;=10)&#123; ++m;//表明该文件输入了一个合法单词 i=0; //调用Hash函数，存入散列表 pos=Make_Hash(word); Storage(word, pos, j); for(int i=10; i&gt;=0; --i)&#123; word[i]=&#x27;\0&#x27;; &#125; &#125;else&#123; for(int i= 10; i&gt;=0; --i)&#123; word[i]=&#x27;\0&#x27;; &#125; i=0; &#125; &#125;//while end //一个文件输入结束后，将m值放入File_word_num中 File_word_num[j]=m; m=0; &#125;&#125;void FindAndRecording(int first, int second)&#123; int find_file[2];//查询文件的编号 int find_result[100]; int a=0; int file_word_num[2]=&#123;0, 0&#125;; for(int i=0; i&lt;100; ++i)&#123; find_result[i]=0; &#125; find_file[0]=first; find_file[1]=second; int common_num=0; Word_node *p=new Word_node; for(int i=0; i&lt;10000; ++i)&#123; p=WORD[i].next; while(p!=NULL)&#123; File_node *q=new File_node; for(int b=0; b&lt;2; ++b)&#123;//对要查询的所有文件 q=p-&gt;file; while(q!=NULL)&#123; if(q-&gt;numbering==find_file[b])&#123; find_result[find_file[b]]=1;//表明该词汇下面有这个文件 file_word_num[b]++; break; &#125; q=q-&gt;next; &#125;//while end &#125; for(int x=0; x&lt;2; ++x)&#123; if (find_result[find_file[x]] == 1)//表明当前位置下面的词汇，是要查询文件的公共词汇 &#123; a++; &#125; &#125; for(int i=0; i&lt;100; ++i)&#123; find_result[i]=0; &#125; if(a==2)&#123; common_num++; &#125; a=0; p=p-&gt;nextword; &#125;//while end &#125;//for end cout&lt;&lt;common_num&lt;&lt;endl; cout&lt;&lt;file_word_num[0]&lt;&lt;endl; cout&lt;&lt;file_word_num[1]&lt;&lt;endl; //输出相似度 printf(&quot;%.1f%%
&quot;, 100*(float)common_num/(file_word_num[0]+ file_word_num[1]-common_num));&#125;void Output()&#123; for(int i=0; i&lt;10000; ++i)&#123; if(WORD[i].next!=NULL)&#123; printf(&quot;WORD[%d]
&quot;, i); Word_node *p=WORD[i].next; while (p!=NULL)&#123; cout&lt;&lt;p-&gt;word&lt;&lt;&quot;:&quot;; File_node *q=p-&gt;file; while(q!=NULL)&#123; cout&lt;&lt;q-&gt;numbering+1&lt;&lt;&quot; &quot;; q=q-&gt;next; &#125; p=p-&gt;nextword; &#125; cout&lt;&lt;endl; &#125; &#125;//for end&#125;int main()&#123; for(int i=0; i&lt;10; ++i)&#123; WORD[i].next=NULL; &#125; Input(); int n; cin&gt;&gt;n; int find[n][2]; for(int i=0; i&lt;n; ++i)&#123; int m, y; cin&gt;&gt;m&gt;&gt;y; find[i][0]=m-1; find[i][1]=y-1; &#125; for(int i=0; i&lt;n; ++i)&#123; FindAndRecording(find[i][0], find[i][1]); &#125; cout&lt;&lt;endl; Output(); return 0;&#125; 实验五 快速排序 #include &quot;iostream&quot;#include &quot;string&quot;using namespace std;typedef struct SqList&#123; string student[3][106];&#125;SqList;class Sort&#123; public: int Partition(SqList &amp;L, int low, int high, int tag)&#123; Swap(L, 0, low); Swap(L, 105, low); while(low&lt;high) &#123; while (low &lt; high &amp;&amp; L.student[tag - 1][high].compare(L.student[tag - 1][105]) &gt;= 0 ) &#123; if(L.student[tag - 1][high].compare(L.student[tag - 1][105]) == 0)&#123; if(L.student[0][high].compare(L.student[0][105])&lt;0)&#123; break; &#125; &#125; --high; &#125; Swap(L, low, high); while (low &lt; high &amp;&amp; L.student[tag - 1][low].compare(L.student[tag - 1][105]) &lt;= 0 ) &#123; if(L.student[tag - 1][low].compare(L.student[tag - 1][105]) == 0)&#123; if(L.student[0][low].compare(L.student[0][105])&gt;0)&#123; break; &#125; &#125; ++low; &#125; Swap(L, high, low); &#125; Swap(L, low, 0); return low; //返回枢轴位置 &#125; void Swap(SqList &amp;L, int m, int n)&#123; L.student[0][m].assign(L.student[0][n]); L.student[1][m].assign(L.student[1][n]); L.student[2][m].assign(L.student[2][n]); &#125; void QSort(SqList &amp;L, int low, int high, int tag)&#123; int pivotloc; if(low&lt;high)&#123; pivotloc=Partition(L, low, high, tag); QSort(L, low, pivotloc-1, tag); QSort(L, pivotloc+1, high, tag); &#125; &#125;&#125;;int main()&#123; int n,tag; cin&gt;&gt;n&gt;&gt;tag; SqList L; for(int i=1; i&lt;=n; ++i)&#123; cin&gt;&gt;L.student[0][i]&gt;&gt;L.student[1][i]&gt;&gt;L.student[2][i]; if(L.student[2][i].compare(&quot;100&quot;)==0)&#123; L.student[2][i].assign(&quot;999&quot;); &#125; &#125; Sort test; test.QSort(L, 1, n, tag); for(int i=1; i&lt;=n; ++i)&#123; if(L.student[2][i].compare(&quot;999&quot;)==0)&#123; L.student[2][i].assign(&quot;100&quot;); &#125; cout&lt;&lt;L.student[0][i]&lt;&lt;&quot;	&quot;&lt;&lt;L.student[1][i]&lt;&lt;&quot;	&quot;&lt;&lt;L.student[2][i]&lt;&lt;endl; &#125; return 0;&#125;
